; 湿地帯

name = モイーズ湿地帯・死者の沼
insideName = Swamp of the Dead
level = 30
bgm = dungeon
isOutdoor = true
shadow = dark
sky = redforest
blank = rock
effect = PE_rain
antiWarp = true

; 画像パーツ
━ = stoner
　 = soilr
❖ = soilr
〓 = wood
〰 = water
✜ = stoner
⏃ = woodsd
⏁ = pedestal
⑹ = box

; 敵情報
monsters = スワンプデビル,マウンテンデビル,デーモンインプ,シャドウインプ,サキュバス,見習いサキュバス

; 移動ポイント
(A) = map:モイーズ湿地帯・死霊の森, x:19 ,y:0, way:n, symbol:movev, ask:Go to the next map?
(B) = map:モイーズ湿地帯・死霊の森, x:20 ,y:0, way:n, symbol:movev, ask:Go to the next map?

; 宝箱
box[1] = 悪のサーベル_u,邪悪な弓_u,エルフの弓_u,経験のコイン（大）
box[2] = 復活の粉,特効薬,特効薬,修理の巻物,修理の巻物,エーテル,ポーション,ポーション
box[3] = 罠はない,マジカルボートの巻物,マジカルボートの巻物

