;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] true

@delevent
@wait time=500 cond='(game.party.curX == 16 && WAY != "n") || (game.party.curX == 17 && WAY != "s")'
@walk turn=n cond='game.party.curX == 16 && WAY != "n"'
@walk turn=s cond='game.party.curX == 17 && WAY != "s"'
@wait time=500
@jump storage="main11.scn" target=*pond_1

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@delevent
@wait time=500 cond='WAY != "w"'
@walk turn=w cond='WAY != "w"'
@wait time=500
[texton]
[リーダー f=06]「...?」[k]
The road ahead is strangely lively.[k]
Is this a place where monsters gather? It might be better to be careful.[k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] true

@delevent
@addevent map=モイーズ湿地帯・死霊の森 num=10
@wait time=500 cond='WAY != "w"'
@walk turn=w cond='WAY != "w"'
@wait time=500
@walk move=w
@walk move=w
@wait time=500
@jump storage="main11.scn" target=*pond_2

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] true

@delevent
@wait time=200
[if exp='WAY != "s"']
	@walk turn=s
	@wait time=500
[endif]
@eval exp='game.map.bgm = "crisis"'
@mu f=crisis
[texton]
[リーダー f=05]「...!」[k]
From the swamp ahead, I sensed something incredibly sinister![k]
[textoff]
@wait time=500
@walk move=s
@wait time=500
@walk move=s
@wait time=500 cond='game.party.curY == 9'
@walk move=s cond='game.party.curY == 9'
@wait time=1000
@se f=roar
@fgf c=9010 left=450 top=80
@wait time=500
[texton]
[リーダー f=12]「This is...!」[k]
We beheld a very frightening scene![k]
Countless animated corpses were coming toward us from the swamp, giving off a foul odor![k]
...At this point, it seems like there's no choice but to fight.[k]
[textoff]
@clf

@monster pos=0  name=ゾンビ
@monster pos=1  name=ゾンビ
@monster pos=2  name=ゾンビ
@monster pos=3  name=ゾンビ
@monster pos=4  name=ゾンビ
@monster pos=5  name=ゾンビ
@monster pos=6  name=ゾンビ
@monster pos=7  name=ゾンビ
@monster pos=8  name=ゾンビ
@monster pos=9  name=ゾンビ
@monster pos=10 name=ゾンビ
@monster pos=11 name=ゾンビ
@monster pos=12 name=ゾンビ
